import copy
import re
import xml.etree.ElementTree as ET
from collections.abc import MutableMapping, MutableSequence
from datetime import datetime
from utils.ini_handler import extract_field_paths
from utils.common import setup_logging

logger = setup_logging(log_file_path="log/xml_comparer.log", logger_name="xml_comparer")


class XMLComparer:
    """XML 字符串比较器，支持复杂的 XML 结构比对。

    将 XML 字符串解析为字典后进行比对，支持忽略字段、时间区间判断、长度对比等高级功能。

    Attributes:
        dict1: 解析后的第一个字典
        dict2: 解析后的第二个字典
        differences: 所有差异列表
        ignore_fields: 忽略对比的字段列表
        time_fields: 时间区间字段字典
        length_fields: 长度对比字段列表
    """

    def __init__(self, xml_str_exp, xml_str_act, ignore_fields=None, time_fields=None, length_fields=None):
        """初始化 XML 比较器。

        Args:
            xml_str_exp: 第一个 XML 字符串
            xml_str_act: 第二个 XML 字符串
            ignore_fields (list, optional): 要忽略对比的字段列表
            time_fields (dict, optional): 时间区间字段字典，
                格式为 {字段路径: (开始时间, 结束时间)}
            length_fields (list, optional): 需要对比值长度的字段列表
        """
        print((xml_str_exp, xml_str_act, ignore_fields, time_fields, length_fields))
        self.dict1 = self.xml_to_dict(xml_str_exp)  # 将第一个 XML 字符串解析为字典
        self.dict2 = self.xml_to_dict(xml_str_act)  # 将第二个 XML 字符串解析为字典
        self.dict2_keys_str = "\n".join(extract_field_paths(self.dict2))
        # print(self.dict2)
        self.differences = []  # 存储所有的差异
        self.ignore_fields = ignore_fields if ignore_fields else []  # 设置忽略对比的字段列表
        self.time_fields = self.parse_time_fields(time_fields) if time_fields else {}  # 解析时间字段
        self.length_fields = length_fields if length_fields else []  # 设置长度对比字段列表

        # 对参数字段没有中，如果使用monitorResult.log.gatherTime字段的更新为log[0]、log[1]
        tmp = list()
        for field_str in self.ignore_fields:
            fields = field_str.split(".")
            pattern = fields[0]
            for key in fields[1:-1]:
                if not key.endswith("]"):
                    pattern += r"\." + key + r"(?:\[\d+?\])*"
                else:
                    pattern += r"\." + key.replace("[", r"\[").replace("]", r"\]")
            if len(fields) >= 2:
                pattern += "." + fields[-1]
            newkeys = re.findall(pattern, self.dict2_keys_str)
            if newkeys:
                tmp += newkeys
        self.ignore_fields = copy.deepcopy(tmp)
        tmp = list()
        for field_str in self.length_fields:
            fields = field_str.split(".")
            pattern = fields[0]
            for key in fields[1:-1]:
                if not key.endswith("]"):
                    pattern += r"\." + key + r"(?:\[\d+?\])*"
                else:
                    pattern += r"\." + key.replace("[", r"\[").replace("]", r"\]")
            if len(fields) >= 2:
                pattern += "." + fields[-1]
            newkeys = re.findall(pattern, self.dict2_keys_str)
            if newkeys:
                tmp += newkeys

        self.length_fields = copy.deepcopy(tmp)
        tmp = dict()
        for field_str, time_value in self.time_fields.items():
            fields = field_str.split(".")
            pattern = fields[0]
            for key in fields[1:-1]:
                if not key.endswith("]"):
                    pattern += r"\." + key + r"(?:\[\d+?\])*"
                else:
                    pattern += r"\." + key.replace("[", r"\[").replace("]", r"\]")
            if len(fields) >= 2:
                pattern += "." + fields[-1]
            newkeys = re.findall(pattern, self.dict2_keys_str)
            if newkeys:
                for new_field in newkeys:
                    tmp[new_field] = time_value
        self.time_fields = copy.deepcopy(tmp)

        # 根据 ignore_fields 更新 length_fields 和 time_fields
        self.length_fields = [field for field in self.length_fields if field not in self.ignore_fields]
        self.time_fields = {field: (start, end, start_formatted, end_formatted)
                            for field, (start, end, start_formatted, end_formatted) in self.time_fields.items()
                            if field not in self.ignore_fields}

        # 将 time_fields 加入到 ignore_fields
        self.length_fields += [field for field in self.time_fields.keys() if field not in self.length_fields]

        # print(f"self.ignore_fields: {self.ignore_fields}")
        # print(f"self.length_fields: {self.length_fields}")
        # print(f"self.time_fields: {self.time_fields}")

    def parse_time_fields(self, time_fields):
        """将时间字段中的时间范围字符串转换为时间戳。

        Args:
            time_fields (dict): 时间字段字典，格式为 {字段路径: (开始时间, 结束时间)}

        Returns:
            dict: 转换后的时间戳字典，
                格式为 {字段路径: (开始时间戳, 结束时间戳, 格式化开始时间, 格式化结束时间)}
        """
        result = {}
        for field, (start_time, end_time) in time_fields.items():
            try:
                if type(start_time) == int or str(start_time).isdigit():
                    start_timestamp = int(start_time)
                else:
                    start_timestamp = int(datetime.strptime(start_time, '%Y-%m-%d %H:%M:%S').timestamp())
                start_time_formatted = start_time
            except ValueError:
                start_timestamp = int(start_time)
                start_time_formatted = datetime.fromtimestamp(start_timestamp).strftime('%Y-%m-%d %H:%M:%S')

            try:
                if type(end_time) == int or str(end_time).isdigit():
                    end_timestamp = int(end_time)
                else:
                    end_timestamp = int(datetime.strptime(end_time, '%Y-%m-%d %H:%M:%S').timestamp())
                end_time_formatted = end_time
            except ValueError:
                end_timestamp = int(end_time)
                end_time_formatted = datetime.fromtimestamp(end_timestamp).strftime('%Y-%m-%d %H:%M:%S')

            result[field] = (start_timestamp, end_timestamp, start_time_formatted, end_time_formatted)
        return result

    def compare(self):
        """比较两个 XML 字典并输出所有差异。

        Returns:
            bool: 如果两个 XML 字符串相同返回 True，否则返回 False
        """
        self.compare_dicts(self.dict1, self.dict2)
        if self.differences:
            for diff in self.differences:
                print(diff)
            return False
        return True

    def compare_values(self, val1, val2, path=''):
        """比较两个值，支持字典、列表和基本类型。

        Args:
            val1: 第一个值
            val2: 第二个值
            path (str, optional): 当前字段路径
        """
        if path in self.ignore_fields:
            return

        if path in self.length_fields:
            if len(str(val1)) != len(str(val2)):
                self.differences.append(f"不一致在 {path}: 长度不同 {len(val1)} != {len(val2)}")
            return

        # 处理时间字段
        if path in self.time_fields:
            start, end, start_formatted, end_formatted = self.time_fields[path]

            # 对比长度
            if isinstance(val1, str) and isinstance(val2, str) and len(val1) != len(val2):
                self.differences.append(f"不一致在 {path}: 长度不同 {len(val1)} != {len(val2)}")
                return

            # 进行时间区间判断
            try:
                # 尝试将 val1 和 val2 转换为时间戳
                time_val1 = int(val1)
                time_val2 = int(val2)
            except ValueError:
                try:
                    time_val1 = int(datetime.strptime(val1, '%Y-%m-%d %H:%M:%S').timestamp())
                except ValueError:
                    self.differences.append(f"时间字段格式错误在 {path}: {val1}")
                    return

                try:
                    time_val2 = int(datetime.strptime(val2, '%Y-%m-%d %H:%M:%S').timestamp())
                except ValueError:
                    self.differences.append(f"时间字段格式错误在 {path}: {val2}")
                    return

            # 对比时间区间
            if not (start <= time_val2 <= end):
                self.differences.append(
                    f"不一致在 {path}: {val2} 不在时间区间 {start_formatted} 到 {end_formatted} 之间")
            return

        # 通用字段值比较
        if isinstance(val1, MutableMapping) and isinstance(val2, MutableMapping):
            self.compare_dicts(val1, val2, path)
        elif isinstance(val1, MutableSequence) and isinstance(val2, MutableSequence):
            self.compare_lists(val1, val2, path)
        else:
            if val1 != val2:
                self.differences.append(f"不一致在 {path}: {val1} != {val2}")

    def compare_dicts(self, dict1, dict2, path=''):
        """
        比较两个字典的函数，递归比较其所有键和值。

        :param dict1: 第一个字典
        :param dict2: 第二个字典
        :param path: 当前字段的路径（用于输出差异）
        """
        keys1 = set(dict1.keys())
        keys2 = set(dict2.keys())

        all_keys = keys1 | keys2  # 获取所有键的集合
        for key in all_keys:
            new_path = f"{path}.{key}" if path else key
            if key in dict1 and key in dict2:
                self.compare_values(dict1[key], dict2[key], new_path)
            elif key in dict1:
                if new_path not in self.ignore_fields:
                    self.differences.append(f"不一致在 {new_path}: {dict1[key]} != None")
            else:
                if new_path not in self.ignore_fields:
                    self.differences.append(f"不一致在 {new_path}: None != {dict2[key]}")

    def compare_lists(self, list1, list2, path=''):
        """
        比较两个列表的函数，递归比较其所有元素。

        :param list1: 第一个列表
        :param list2: 第二个列表
        :param path: 当前字段的路径（用于输出差异）
        """
        if len(list1) != len(list2):
            self.differences.append(f"不一致在 {path}: 列表长度不同 {len(list1)} != {len(list2)}")
            return

        # # 对列表进行排序以确保比较顺序一致
        # list1_sorted = sorted(list1, key=lambda x: self.sort_key(x))
        # list2_sorted = sorted(list2, key=lambda x: self.sort_key(x))
        list1_sorted = list1
        list2_sorted = list2
        for index, (item1, item2) in enumerate(zip(list1_sorted, list2_sorted)):
            new_path = f"{path}[{index}]"
            self.compare_values(item1, item2, new_path)

    def sort_key(self, item):
        """
        为列表中的字典项目提供排序键。

        :param item: 项目
        :return: 排序键（对于字典项目，按键值对排序；对于其他项，直接使用项本身）
        """
        if isinstance(item, MutableMapping):
            return sorted(item.items())
        return item

    def parse_element(self, element):
        """
        递归解析 XML 元素为字典。

        :param element: XML 元素
        :return: 解析后的字典
        """
        if list(element):
            result = {}
            for child in element:
                child_dict = self.parse_element(child)
                if child.tag in result:
                    if not isinstance(result[child.tag], list):
                        result[child.tag] = [result[child.tag]]
                    result[child.tag].append(child_dict)
                else:
                    result[child.tag] = child_dict
            return result
        else:
            try:
                return int(element.text)
            except (TypeError, ValueError):
                try:
                    return float(element.text)
                except (TypeError, ValueError):
                    return element.text

    def xml_to_dict(self, xml_str):
        """
        将 XML 字符串转换为字典。

        :param xml_str: XML 字符串
        :return: 转换后的字典
        """
        root = ET.fromstring(xml_str)
        return {root.tag: self.parse_element(root)}


